    returned_state = request.args.get("state")
    expected_state = session.pop("oidc_state", None)

    if not returned_state or not expected_state:
        logger.error("Missing state parameter")
        abort(400, description="Missing state parameter")

    if not secrets.compare_digest(returned_state, expected_state):
        logger.error("State parameter mismatch - possible CSRF attack")
        abort(400, description="Invalid state parameter")

    # Check that the auth flow hasn't been sitting too long (5 min max)
    auth_started_at = session.pop("oidc_auth_started_at", 0)
    if time.time() - auth_started_at > 300:
        logger.error("Authentication flow expired")
        abort(400, description="Authentication flow expired. Please try again.")

    # --- Get the authorization code ---
    authorization_code = request.args.get("code")
    if not authorization_code:
        logger.error("No authorization code in callback")
        abort(400, description="Missing authorization code")

    # --- Exchange code for tokens ---
